/**
 * Recall — on-demand transcript sync + latest session lookup.
 * Port of scripts/recall-session.py
 */

import { existsSync, readFileSync } from 'node:fs'
import { resolve, join } from 'node:path'

import initSqlJs from 'sql.js'

import { slugify } from '../transcript/common.js'
import { defaultGlobalTranscriptRoot, discoverSourceFiles, transcriptMatchesRepo } from '../transcript/discover.js'
import { importTranscript, transcriptHasContent } from '../transcript/import.js'
import { parseTranscript } from '../transcript/parse.js'
import { toPosixPath } from '../utils/path.js'

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface RecallResult {
  found: boolean
  project: string
  repo: string
  imported_count: number
  message?: string
  client?: string
  session_id?: string
  title?: string
  started_at?: string
  cwd?: string
  branch?: string
  message_count?: number
  tool_event_count?: number
  global_clean_path?: string
  clean_content?: string
}

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

export async function recall(
  root: string,
  projectName: string,
  globalRootOverride: string,
  activationTime: string,
): Promise<RecallResult> {
  const resolvedRoot = resolve(root)
  const repoSlug = slugify(projectName.trim() || (resolvedRoot.split(/[/\\]/).pop() ?? ''), 'project')
  const globalRoot = globalRootOverride ? resolve(globalRootOverride) : defaultGlobalTranscriptRoot()
  const effectiveActivation = activationTime || nowIso()

  const imported = await syncCurrentProject(resolvedRoot, repoSlug, globalRoot)

  const session = await findLatestSession(globalRoot, resolvedRoot, repoSlug, effectiveActivation)

  if (session === null) {
    return {
      found: false,
      project: repoSlug,
      repo: toPosixPath(resolvedRoot),
      imported_count: imported,
      message: 'No previous session found for this project.',
    }
  }

  const cleanPath = String(session['global_clean_path'] ?? '')
  let cleanContent = ''
  if (cleanPath && existsSync(cleanPath)) {
    try {
      cleanContent = readFileSync(cleanPath, 'utf-8')
    } catch {
      // ignore read errors
    }
  }

  return {
    found: true,
    project: repoSlug,
    repo: toPosixPath(resolvedRoot),
    imported_count: imported,
    client: String(session['client'] ?? ''),
    session_id: String(session['session_id'] ?? ''),
    title: String(session['title'] ?? ''),
    started_at: String(session['started_at'] ?? ''),
    cwd: String(session['cwd'] ?? ''),
    branch: String(session['branch'] ?? ''),
    message_count: Number(session['message_count'] ?? 0),
    tool_event_count: Number(session['tool_event_count'] ?? 0),
    global_clean_path: cleanPath,
    clean_content: cleanContent,
  }
}

// ---------------------------------------------------------------------------
// Sync current project
// ---------------------------------------------------------------------------

export async function syncCurrentProject(root: string, repoSlug: string, globalRoot: string): Promise<number> {
  const discovered = discoverSourceFiles()
  let imported = 0

  for (const [client, source] of discovered) {
    let parsed
    try {
      parsed = parseTranscript(client, source)
    } catch {
      continue
    }

    if (!transcriptHasContent(parsed)) continue
    if (!transcriptMatchesRepo(parsed, root, repoSlug)) continue

    try {
      await importTranscript(parsed, root, globalRoot, repoSlug, 'not-set', true)
      imported++
    } catch {
      continue
    }
  }

  return imported
}

// ---------------------------------------------------------------------------
// Find latest session
// ---------------------------------------------------------------------------

export async function findLatestSession(
  globalRoot: string,
  root: string,
  repoSlug: string,
  activationTime: string,
): Promise<Record<string, unknown> | null> {
  const dbPath = join(globalRoot, 'index', 'search.sqlite')
  if (!existsSync(dbPath)) {
    return findLatestFromJsonl(globalRoot, root, repoSlug, activationTime)
  }

  try {
    const SQL = await initSqlJs()
    const db = new SQL.Database(readFileSync(dbPath))
    try {
      const stmt = db.prepare(
        'SELECT * FROM transcripts WHERE started_at < ? ORDER BY started_at DESC LIMIT 20',
      )
      stmt.bind([activationTime])

      const resolvedRoot = toPosixPath(resolve(root)).toLowerCase()
      const columns = stmt.getColumnNames()

      while (stmt.step()) {
        const values = stmt.get()
        const row: Record<string, unknown> = {}
        for (let i = 0; i < columns.length; i++) {
          row[columns[i]!] = values[i]
        }
        const cwd = String(row['cwd'] ?? '')
        const project = String(row['project'] ?? '')
        if (cwdMatches(cwd, resolvedRoot) || project === repoSlug) {
          stmt.free()
          return row
        }
      }
      stmt.free()
    } finally {
      db.close()
    }
  } catch {
    return findLatestFromJsonl(globalRoot, root, repoSlug, activationTime)
  }

  return null
}

// ---------------------------------------------------------------------------
// JSONL fallback
// ---------------------------------------------------------------------------

export function findLatestFromJsonl(
  globalRoot: string,
  root: string,
  repoSlug: string,
  activationTime: string,
): Record<string, unknown> | null {
  const jsonlPath = join(globalRoot, 'index', 'sessions.jsonl')
  if (!existsSync(jsonlPath)) return null

  const resolvedRoot = toPosixPath(resolve(root)).toLowerCase()
  const candidates: Record<string, unknown>[] = []

  let content: string
  try {
    content = readFileSync(jsonlPath, 'utf-8')
  } catch {
    return null
  }

  for (const line of content.split('\n')) {
    const trimmed = line.trim()
    if (!trimmed) continue
    let entry: Record<string, unknown>
    try {
      entry = JSON.parse(trimmed) as Record<string, unknown>
    } catch {
      continue
    }

    const started = String(entry['started_at'] ?? '')
    if (started >= activationTime) continue

    const cwd = String(entry['cwd'] ?? '')
    const project = String(entry['project'] ?? '')
    if (cwdMatches(cwd, resolvedRoot) || project === repoSlug) {
      candidates.push(entry)
    }
  }

  if (candidates.length === 0) return null

  candidates.sort((a, b) => {
    const aTime = String(a['started_at'] ?? '')
    const bTime = String(b['started_at'] ?? '')
    return bTime.localeCompare(aTime)
  })
  return candidates[0]!
}

// ---------------------------------------------------------------------------
// CWD matching
// ---------------------------------------------------------------------------

export function cwdMatches(cwd: string, resolvedRoot: string): boolean {
  if (!cwd) return false
  try {
    const cwdResolved = toPosixPath(resolve(cwd)).toLowerCase()
    if (cwdResolved === resolvedRoot) return true
    const prefix = resolvedRoot.endsWith('/') ? resolvedRoot : resolvedRoot + '/'
    return cwdResolved.startsWith(prefix)
  } catch {
    return false
  }
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function nowIso(): string {
  return new Date().toISOString().replace(/\.\d{3}Z$/, 'Z')
}

export function formatText(payload: RecallResult): string {
  if (!payload.found) {
    return [
      `project: ${payload.project}`,
      `imported: ${payload.imported_count}`,
      `result: ${payload.message ?? 'No previous session found.'}`,
    ].join('\n')
  }

  const lines = [
    `project: ${payload.project}`,
    `client: ${payload.client ?? ''}`,
    `session_id: ${payload.session_id ?? ''}`,
    `title: ${payload.title ?? ''}`,
    `started_at: ${payload.started_at ?? ''}`,
    `cwd: ${payload.cwd ?? ''}`,
    `branch: ${payload.branch ?? ''}`,
    `messages: ${payload.message_count ?? 0}`,
    `tool_events: ${payload.tool_event_count ?? 0}`,
    `imported_this_sync: ${payload.imported_count}`,
    `clean_transcript: ${payload.global_clean_path ?? ''}`,
  ]

  if (payload.clean_content) {
    lines.push('', '--- clean transcript content ---', payload.clean_content)
  }

  return lines.join('\n')
}

/**
 * MemoryTree heartbeat — single execution, stateless, idempotent.
 * Port of scripts/heartbeat.py
 */

import type { ParsedTranscript } from '../types/transcript.js'
import { discoverSourceFiles, transcriptMatchesRepo } from '../transcript/discover.js'
import { importTranscript, transcriptHasContent } from '../transcript/import.js'
import { parseTranscript } from '../transcript/parse.js'
import { slugify } from '../transcript/common.js'
import { defaultGlobalTranscriptRoot } from '../transcript/discover.js'
import type { Config } from './config.js'
import { loadConfig } from './config.js'
import { acquireLock, releaseLock } from './lock.js'
import { resetFailureCount, writeAlert, writeAlertWithThreshold } from './alert.js'
import type { LogLevel } from './log.js'
import { getLogger, setupLogging } from './log.js'
import { git } from '../utils/exec.js'
import { toPosixPath } from '../utils/path.js'
import { resolve } from 'node:path'
import { existsSync } from 'node:fs'

// ---------------------------------------------------------------------------
// Sensitive pattern detection
// ---------------------------------------------------------------------------

const SENSITIVE_PATTERNS: readonly RegExp[] = [
  /(?:api[_-]?key|apikey)\s*[:=]\s*\S+/i,
  /(?:password|passwd|pwd)\s*[:=]\s*\S+/i,
  /(?:secret|token)\s*[:=]\s*\S+/i,
  /(?:sk-|pk_live_|sk_live_|ghp_|gho_|glpat-)\S{10,}/,
  /Bearer\s+\S{20,}/i,
]

// ---------------------------------------------------------------------------
// Main entry point
// ---------------------------------------------------------------------------

export async function main(): Promise<number> {
  const config = loadConfig()
  setupLogging(config.log_level as LogLevel)
  const logger = getLogger()

  if (!acquireLock()) {
    logger.info('Another heartbeat instance is running. Exiting.')
    writeAlert('global', 'lock_held', 'Heartbeat exited: another instance held the lock.')
    return 0
  }

  try {
    return await runHeartbeat(config)
  } finally {
    releaseLock()
  }
}

// ---------------------------------------------------------------------------
// Heartbeat orchestration
// ---------------------------------------------------------------------------

export async function runHeartbeat(config: Config): Promise<number> {
  const logger = getLogger()

  if (config.projects.length === 0) {
    logger.info('No projects registered in config.toml. Nothing to do.')
    return 0
  }

  logger.info(`Heartbeat started. ${config.projects.length} project(s) registered.`)

  for (const entry of config.projects) {
    const projectPath = resolve(entry.path)
    if (!existsSync(projectPath)) {
      logger.warn(`Project path does not exist, skipping: ${projectPath}`)
      continue
    }
    try {
      await processProject(config, projectPath, entry.name || (projectPath.split(/[/\\]/).pop() ?? ''))
    } catch (err: unknown) {
      logger.exception(`Error processing project: ${projectPath}`, err)
      writeAlertWithThreshold(
        toPosixPath(projectPath),
        'push_failed',
        `Heartbeat error for project: ${projectPath.split(/[/\\]/).pop() ?? ''}`,
      )
    }
  }

  logger.info('Heartbeat finished.')
  return 0
}

// ---------------------------------------------------------------------------
// Per-project processing
// ---------------------------------------------------------------------------

export async function processProject(config: Config, projectPath: string, projectName: string): Promise<void> {
  const logger = getLogger()
  const repoSlug = slugify(projectName, 'project')
  const globalRoot = defaultGlobalTranscriptRoot()

  const discovered = discoverSourceFiles()
  let importedCount = 0

  for (const [client, source] of discovered) {
    let parsed: ParsedTranscript
    try {
      parsed = parseTranscript(client, source)
    } catch {
      logger.debug(`Failed to parse ${source}, skipping.`)
      continue
    }

    if (!transcriptHasContent(parsed)) continue
    if (!transcriptMatchesRepo(parsed, projectPath, repoSlug)) continue

    scanSensitive(parsed, projectPath)

    try {
      await importTranscript(parsed, projectPath, globalRoot, repoSlug, 'not-set', true)
      importedCount++
    } catch {
      logger.exception(`Failed to import transcript: ${source}`)
    }
  }

  if (importedCount === 0) {
    logger.info(`[${projectName}] No new transcripts to import.`)
    return
  }

  logger.info(`[${projectName}] Imported ${importedCount} transcript(s).`)
  gitCommitAndPush(config, projectPath, projectName, importedCount)
}

// ---------------------------------------------------------------------------
// Sensitive pattern scanning
// ---------------------------------------------------------------------------

export function scanSensitive(parsed: ParsedTranscript, projectPath: string): void {
  const logger = getLogger()
  for (const msg of parsed.messages) {
    for (const pattern of SENSITIVE_PATTERNS) {
      if (pattern.test(msg.text)) {
        logger.warn(
          `Sensitive pattern detected in transcript ${parsed.source_path} (project: ${projectPath.split(/[/\\]/).pop() ?? ''}, role: ${msg.role})`,
        )
        writeAlert(
          toPosixPath(projectPath),
          'sensitive_match',
          `Sensitive pattern in transcript: ${parsed.source_path.split(/[/\\]/).pop() ?? ''}`,
        )
        return
      }
    }
  }
}

// ---------------------------------------------------------------------------
// Git operations
// ---------------------------------------------------------------------------

export function gitCommitAndPush(config: Config, projectPath: string, projectName: string, count: number): void {
  const logger = getLogger()

  const status = git(projectPath, 'status', '--porcelain', 'Memory/')
  if (!status.trim()) {
    logger.info(`[${projectName}] No git changes in Memory/.`)
    return
  }

  git(projectPath, 'add', 'Memory/')
  git(projectPath, 'commit', '-m', `memorytree(transcripts): import ${count} transcript(s)`)
  logger.info(`[${projectName}] Committed ${count} transcript import(s).`)

  if (!config.auto_push) {
    logger.info(`[${projectName}] auto_push disabled, skipping push.`)
    return
  }

  const remotes = git(projectPath, 'remote')
  if (!remotes.trim()) {
    logger.warn(`[${projectName}] No git remote configured, skipping push.`)
    writeAlert(toPosixPath(projectPath), 'no_remote', 'Push skipped: no Git remote configured.')
    return
  }

  if (!tryPush(projectPath, projectName)) {
    logger.warn(`[${projectName}] Push failed, retrying once...`)
    if (!tryPush(projectPath, projectName)) {
      logger.error(`[${projectName}] Push failed after retry.`)
      writeAlertWithThreshold(toPosixPath(projectPath), 'push_failed', 'Push failed after retry.')
      return
    }
  }

  resetFailureCount(toPosixPath(projectPath), 'push_failed')
}

export function tryPush(projectPath: string, projectName: string): boolean {
  try {
    git(projectPath, 'push')
    getLogger().info(`[${projectName}] Pushed successfully.`)
    return true
  } catch {
    return false
  }
}

/**
 * Transcript import — orchestration, cleaning, and manifest management.
 * Port of scripts/_transcript_import.py
 */

import { copyFileSync, existsSync, mkdirSync, readFileSync, writeFileSync, appendFileSync } from 'node:fs'
import { dirname, extname, join, relative } from 'node:path'

import type { ManifestEntry, ParsedTranscript } from '../types/transcript.js'
import { toPosixPath } from '../utils/path.js'
import {
  loadJson,
  normalizeTimestamp,
  sha256File,
  slugify,
  timestampPartition,
  yamlEscape,
} from './common.js'
import { upsertSearchIndex } from './db.js'

export async function importTranscript(
  parsed: ParsedTranscript,
  root: string,
  globalRoot: string,
  projectSlug: string,
  rawUploadPermission: string,
  mirrorToRepo = true,
): Promise<ManifestEntry> {
  const importedAt = normalizeTimestamp(new Date())
  const rawSha256 = sha256File(parsed.source_path)
  const sessionLabel = slugify(
    parsed.session_id,
    slugify(stemOf(parsed.source_path), 'session'),
  )
  const artifactStem = `${sessionLabel}__${rawSha256.slice(0, 8)}`
  const sourceSuffix = extname(parsed.source_path) || '.txt'

  const [yearToken, monthToken] = timestampPartition(parsed.started_at || importedAt)

  const repoRoot = join(root, 'Memory', '06_transcripts')
  const repoRawPath = join(repoRoot, 'raw', parsed.client, yearToken, monthToken, `${artifactStem}${sourceSuffix}`)
  const repoCleanPath = join(repoRoot, 'clean', parsed.client, yearToken, monthToken, `${artifactStem}.md`)
  const repoManifestPath = join(repoRoot, 'manifests', parsed.client, yearToken, monthToken, `${artifactStem}.json`)

  const globalRawPath = join(globalRoot, 'raw', parsed.client, projectSlug, yearToken, monthToken, `${artifactStem}${sourceSuffix}`)
  const globalCleanPath = join(globalRoot, 'clean', parsed.client, projectSlug, yearToken, monthToken, `${artifactStem}.md`)
  const globalManifestPath = join(globalRoot, 'index', 'manifests', parsed.client, projectSlug, yearToken, monthToken, `${artifactStem}.json`)
  const globalEventLogPath = join(globalRoot, 'index', 'sessions.jsonl')
  const globalDbPath = join(globalRoot, 'index', 'search.sqlite')

  for (const p of [globalRawPath, globalCleanPath, globalManifestPath, globalEventLogPath, globalDbPath]) {
    mkdirSync(dirname(p), { recursive: true })
  }
  if (mirrorToRepo) {
    for (const p of [repoRawPath, repoCleanPath, repoManifestPath]) {
      mkdirSync(dirname(p), { recursive: true })
    }
  }

  if (mirrorToRepo) {
    copyFile(parsed.source_path, repoRawPath)
  }
  copyFile(parsed.source_path, globalRawPath)

  let manifest: ManifestEntry = {
    client: parsed.client,
    project: projectSlug,
    session_id: parsed.session_id,
    title: parsed.title,
    started_at: parsed.started_at,
    imported_at: importedAt,
    cwd: parsed.cwd,
    branch: parsed.branch,
    raw_source_path: toPosixPath(parsed.source_path),
    raw_sha256: rawSha256,
    raw_upload_permission: rawUploadPermission,
    repo_raw_path: mirrorToRepo ? toPosixPath(relative(root, repoRawPath)) : '',
    repo_clean_path: mirrorToRepo ? toPosixPath(relative(root, repoCleanPath)) : '',
    repo_manifest_path: mirrorToRepo ? toPosixPath(relative(root, repoManifestPath)) : '',
    global_raw_path: toPosixPath(globalRawPath),
    global_clean_path: toPosixPath(globalCleanPath),
    global_manifest_path: toPosixPath(globalManifestPath),
    message_count: parsed.messages.length,
    tool_event_count: parsed.tool_events.length,
    cleaning_mode: 'deterministic-code',
    repo_mirror_enabled: mirrorToRepo,
  }

  const existingGlobalManifest = loadJson(globalManifestPath)
  manifest = preserveExistingImportTimestamp(existingGlobalManifest, manifest)

  if (mirrorToRepo) {
    writeCleanMarkdown(parsed, manifest, repoCleanPath)
  }
  writeCleanMarkdown(parsed, manifest, globalCleanPath)
  const manifestRecord = { ...manifest } as Record<string, unknown>
  if (mirrorToRepo) {
    writeJson(repoManifestPath, manifestRecord)
  }
  const appendToEventLog = existingGlobalManifest === null || !deepEqual(existingGlobalManifest, manifestRecord)
  writeJson(globalManifestPath, manifestRecord)
  if (appendToEventLog) {
    appendJsonl(globalEventLogPath, manifestRecord)
  }
  await upsertSearchIndex(globalDbPath, manifest)

  return manifest
}

export function transcriptHasContent(parsed: ParsedTranscript): boolean {
  return parsed.messages.length > 0 || parsed.tool_events.length > 0
}

export function writeCleanMarkdown(parsed: ParsedTranscript, manifest: ManifestEntry, filePath: string): void {
  const lines: string[] = [
    '---',
    `client: ${manifest.client}`,
    `project: ${manifest.project}`,
    `session_id: ${manifest.session_id}`,
    `title: ${yamlEscape(manifest.title)}`,
    `started_at: ${manifest.started_at}`,
    `imported_at: ${manifest.imported_at}`,
    `cwd: ${yamlEscape(manifest.cwd)}`,
    `branch: ${yamlEscape(manifest.branch)}`,
    `raw_source_path: ${yamlEscape(manifest.raw_source_path)}`,
    `raw_sha256: ${manifest.raw_sha256}`,
    `raw_upload_permission: ${manifest.raw_upload_permission}`,
    `cleaning_mode: ${manifest.cleaning_mode}`,
    '---',
    '',
    `# ${manifest.title || manifest.session_id}`,
    '',
    '## Metadata',
    `- Client: \`${manifest.client}\``,
    `- Project: \`${manifest.project}\``,
    `- Session ID: \`${manifest.session_id}\``,
    `- Started At: \`${manifest.started_at}\``,
    `- Imported At: \`${manifest.imported_at}\``,
    `- Raw SHA256: \`${manifest.raw_sha256}\``,
    `- Raw Source: \`${manifest.raw_source_path}\``,
    `- Repo Raw Path: \`${manifest.repo_raw_path}\``,
    `- Repo Clean Path: \`${manifest.repo_clean_path}\``,
    '',
    '## Messages',
  ]

  if (parsed.messages.length > 0) {
    for (let i = 0; i < parsed.messages.length; i++) {
      const message = parsed.messages[i]!
      lines.push(
        `### ${i + 1}. ${message.role}`,
        `- Timestamp: \`${message.timestamp ?? manifest.started_at}\``,
        '',
        message.text,
        '',
      )
    }
  } else {
    lines.push(
      'No user or assistant messages were extracted deterministically from the source transcript.',
      '',
    )
  }

  lines.push('## Tool Events')
  if (parsed.tool_events.length > 0) {
    for (const event of parsed.tool_events) {
      lines.push(`- \`${event.timestamp ?? manifest.started_at}\` ${event.summary}`)
    }
  } else {
    lines.push('- No tool events were extracted.')
  }
  lines.push('')

  writeFileSync(filePath, lines.join('\n'), 'utf-8')
}

export function preserveExistingImportTimestamp(
  existing: Record<string, unknown> | null,
  payload: ManifestEntry,
): ManifestEntry {
  if (existing === null) return payload
  const payloadRecord = { ...payload } as Record<string, unknown>
  if (!deepEqual(manifestSignature(existing), manifestSignature(payloadRecord))) return payload
  const importedAt = existing['imported_at']
  if (typeof importedAt === 'string' && importedAt) {
    return { ...payload, imported_at: importedAt }
  }
  return payload
}

export function manifestSignature(payload: Record<string, unknown>): Record<string, unknown> {
  const result: Record<string, unknown> = {}
  for (const [key, value] of Object.entries(payload)) {
    if (key !== 'imported_at') {
      result[key] = value
    }
  }
  return result
}

export function manifestChanged(filePath: string, payload: Record<string, unknown>): boolean {
  if (!existsSync(filePath)) return true
  try {
    const current = JSON.parse(readFileSync(filePath, 'utf-8')) as Record<string, unknown>
    return !deepEqual(current, payload)
  } catch {
    return true
  }
}

export function writeJson(filePath: string, payload: Record<string, unknown>): void {
  writeFileSync(filePath, JSON.stringify(payload, null, 2) + '\n', 'utf-8')
}

export function appendJsonl(filePath: string, payload: Record<string, unknown>): void {
  appendFileSync(filePath, JSON.stringify(payload) + '\n', 'utf-8')
}

export function copyFile(source: string, destination: string): void {
  if (source === destination) return
  copyFileSync(source, destination)
}

// ---------------------------------------------------------------------------
// Internal helpers
// ---------------------------------------------------------------------------

function stemOf(filePath: string): string {
  const base = filePath.replace(/\\/g, '/').split('/').pop() ?? ''
  const ext = extname(base)
  return ext ? base.slice(0, -ext.length) : base
}

function deepEqual(a: unknown, b: unknown): boolean {
  if (a === b) return true
  if (a === null || b === null || typeof a !== typeof b) return false
  if (typeof a !== 'object') return false
  if (Array.isArray(a) !== Array.isArray(b)) return false
  const aObj = a as Record<string, unknown>
  const bObj = b as Record<string, unknown>
  const aKeys = Object.keys(aObj)
  const bKeys = Object.keys(bObj)
  if (aKeys.length !== bKeys.length) return false
  return aKeys.every(key => deepEqual(aObj[key], bObj[key]))
}

/**
 * Upgrade — upgrade detection + execution.
 * Port of scripts/upgrade-memorytree.py
 */

import { existsSync, readFileSync, statSync } from 'node:fs'
import { join } from 'node:path'

import {
  createMemoryDirs,
  findExternalPolicySources,
  findLatestChatLogFile,
  findLatestGoalFile,
  findLatestTodoFile,
  resolveScaffoldPaths,
  scaffoldContentFiles,
  writeTemplate,
} from './scaffold.js'

// ---------------------------------------------------------------------------
// State detection
// ---------------------------------------------------------------------------

export function detectState(root: string): string {
  const memoryDir = join(root, 'Memory')
  const goalDir = join(root, 'Memory', '01_goals')
  const todoDir = join(root, 'Memory', '02_todos')
  const chatDir = join(root, 'Memory', '03_chat_logs')
  const agentsPath = join(root, 'AGENTS.md')
  const policySources = findExternalPolicySources(root)

  const latestGoal = findLatestGoalFile(goalDir)
  const goalVersion = extractGoalVersion(latestGoal)
  const hasGoal = latestGoal !== null
  const hasTodo = goalVersion !== null && findLatestTodoFile(todoDir, goalVersion) !== null
  const hasChat = findLatestChatLogFile(chatDir) !== null
  const hasAgents = existsSync(agentsPath) && isFile(agentsPath)
  const agentsReady = hasAgents && !needsAgentsMerge(agentsPath)

  if (!existsSync(memoryDir)) {
    return (hasAgents || policySources.length > 0) ? 'partial' : 'not-installed'
  }
  if (hasGoal && hasTodo && hasChat && agentsReady) {
    return 'installed'
  }
  return 'partial'
}

export function extractGoalVersion(filePath: string | null): string | null {
  if (filePath === null) return null
  const name = filePath.replace(/\\/g, '/').split('/').pop() ?? ''
  const match = /^goal_v(\d{3})_\d{8}\.md$/.exec(name)
  return match?.[1] ?? null
}

// ---------------------------------------------------------------------------
// AGENTS.md completeness check (9 signals)
// ---------------------------------------------------------------------------

export function needsAgentsMerge(agentsPath: string): boolean {
  let text: string
  try {
    text = readFileSync(agentsPath, 'utf-8').toLowerCase()
  } catch {
    return true
  }

  const checks = [
    hasReadOrderSignal(text),
    hasMemoryLayoutSignal(text),
    hasActiveTodoRule(text),
    hasAppendOnlyChatLogRule(text),
    hasRepoSafetyRule(text),
    hasCommitTitleRule(text),
    hasDedicatedMemorytreePrFlow(text),
    hasMemorytreeOnlyScopeRule(text),
    hasAutoMergeRule(text),
  ]
  return !checks.every(Boolean)
}

// ---------------------------------------------------------------------------
// Signal detectors
// ---------------------------------------------------------------------------

function matchesAny(text: string, patterns: readonly RegExp[]): boolean {
  return patterns.some(p => p.test(text))
}

function matchesAllConcepts(text: string, groups: readonly (readonly RegExp[])[]): boolean {
  return groups.every(patterns => matchesAny(text, patterns))
}

export function hasReadOrderSignal(text: string): boolean {
  return matchesAny(text, [
    /\bread order\b/, /\bread .* in order\b/, /读取顺序/, /按此顺序读取/,
  ])
}

export function hasMemoryLayoutSignal(text: string): boolean {
  return matchesAllConcepts(text, [
    [/memory\/01_goals/, /\b01_goals\b/],
    [/memory\/02_todos/, /\b02_todos\b/],
    [/memory\/03_chat_logs/, /\b03_chat_logs\b/],
  ])
}

export function hasActiveTodoRule(text: string): boolean {
  return matchesAny(text, [
    /keep .*todo .*synchron/,
    /todo .*aligned .*active goal/,
    /(sync|align|keep|maintain|bind).{0,50}(active|current).{0,20}todo.{0,50}(active|current).{0,20}goal/,
    /(active|current).{0,20}todo.{0,50}(sync|align|match|bound).{0,50}(active|current).{0,20}goal/,
    /当前待办必须与当前目标保持同步/,
    /待办必须与当前目标保持同步/,
  ])
}

export function hasAppendOnlyChatLogRule(text: string): boolean {
  return matchesAny(text, [
    /append[- ]only .*chat log/,
    /append[- ]only records/,
    /treat chat logs as append[- ]only/,
    /never rewrite or delete prior entries/,
    /对话日志只追加/,
    /禁止重写或删除既有内容/,
  ])
}

export function hasRepoSafetyRule(text: string): boolean {
  return matchesAllConcepts(text, [
    [/\bpr\b/, /\bpull request\b/, /\bmerge request\b/, /拉取请求/, /合并请求/],
    [/\bci\b/, /\bchecks?\b/, /\bpipeline\b/, /\be2e\b/, /检查/, /流水线/],
    [/\breview(?:er|ers)?\b/, /\bapproval(?:s)?\b/, /评审/, /审批/],
    [/\bbranch(?:es)?\b/, /\bprotected branch(?:es)?\b/, /分支/],
  ]) && matchesAny(text, [
    /\brepository\b/, /\brepo\b/, /\bproject\b/, /\bhost\b/,
    /\brule(?:s)?\b/, /\brequirement(?:s)?\b/, /\bpolicy\b/, /\bcontrol(?:s)?\b/,
    /仓库/, /规则/, /要求/,
  ])
}

export function hasCommitTitleRule(text: string): boolean {
  return matchesAny(text, [
    /\bmemorytree\([^)]*\):/, /\b[a-z]+\((memorytree)\):/,
    /\bmemorytree:/, /memorytree-scoped commit title/,
    /memorytree-specific commit title/, /use .*memorytree.*commit title/,
    /提交标题.*memorytree/,
  ])
}

export function hasDedicatedMemorytreePrFlow(text: string): boolean {
  return matchesAllConcepts(text, [
    [/\bmemorytree\b/, /记忆/],
    [/\bbranch(?:es)?\b/, /分支/],
    [/\bpr\b/, /\bpull request\b/, /\bmerge request\b/, /拉取请求/, /合并请求/],
    [/\bdedicated\b/, /\bseparate\b/, /\bisolated\b/, /\bown\b/, /专用/, /独立/],
  ])
}

export function hasMemorytreeOnlyScopeRule(text: string): boolean {
  return matchesAny(text, [
    /memorytree[- ]owned changes/,
    /memorytree[- ]owned files/,
    /memorytree-managed files/,
    /(stage|push|commit).{0,40}only.{0,40}memorytree[- ]owned.{0,20}(files|changes)?/,
    /(stage|push|commit).{0,40}only.{0,40}memorytree.{0,20}(files|changes|diff)/,
    /only.{0,40}memorytree.{0,20}(files|changes|diff)/,
    /仅自动提交和推送.*memorytree.*变更/,
    /由 memorytree 管理/,
  ])
}

export function hasAutoMergeRule(text: string): boolean {
  return matchesAny(text, [
    /auto-merge only when .*permit/,
    /only when repository rules permit/,
    /only when repo rules permit/,
    /only enable auto-merge when.{0,60}(required )?(approvals|checks|reviews?)/,
    /auto-merge.{0,60}(required approvals|required checks|repository rules)/,
    /仅在仓库规则允许时才开启自动合并/,
  ])
}

// ---------------------------------------------------------------------------
// Upgrade execution
// ---------------------------------------------------------------------------

export interface UpgradeResult {
  state_before: string
  state_after: string
  requested_locale: string
  effective_locale: string
  created_dirs: string[]
  created_files: string[]
  preserved_files: string[]
  agents_action: string
  agents_merge_required: boolean
}

export function upgrade(
  root: string,
  skillRoot: string,
  templates: string,
  effectiveLocale: string,
  requestedLocale: string,
  goalSummary: string,
  projectName: string,
  dt: Date,
): UpgradeResult {
  const initialState = detectState(root)

  const createdDirs = createMemoryDirs(root)
  const paths = resolveScaffoldPaths(root, dt)
  const { created: createdFiles, preserved: preservedFiles } = scaffoldContentFiles(
    paths, templates, goalSummary, projectName, false,
  )

  const agentsPath = join(root, 'AGENTS.md')
  let agentsAction = 'preserved_existing'
  if (!existsSync(agentsPath)) {
    const agentsTemplate = join(templates, 'agents.md')
    if (existsSync(agentsTemplate) && writeTemplate(agentsTemplate, agentsPath, false, {})) {
      createdFiles.push('AGENTS.md')
      agentsAction = 'created'
    }
  } else {
    preservedFiles.push('AGENTS.md')
  }
  const mergeRequired = agentsAction === 'preserved_existing' && needsAgentsMerge(agentsPath)

  return {
    state_before: initialState,
    state_after: detectState(root),
    requested_locale: requestedLocale,
    effective_locale: effectiveLocale,
    created_dirs: createdDirs,
    created_files: createdFiles,
    preserved_files: preservedFiles,
    agents_action: agentsAction,
    agents_merge_required: mergeRequired,
  }
}

export function formatResultText(result: UpgradeResult): string {
  const lines = [
    `state_before: ${result.state_before}`,
    `state_after: ${result.state_after}`,
    `effective_locale: ${result.effective_locale}`,
    `agents_action: ${result.agents_action}`,
    `agents_merge_required: ${result.agents_merge_required}`,
  ]
  if (result.created_dirs.length > 0) {
    lines.push('created_dirs:')
    for (const item of result.created_dirs) lines.push(`- ${item}`)
  }
  if (result.created_files.length > 0) {
    lines.push('created_files:')
    for (const item of result.created_files) lines.push(`- ${item}`)
  }
  if (result.preserved_files.length > 0) {
    lines.push('preserved_files:')
    for (const item of result.preserved_files) lines.push(`- ${item}`)
  }
  return lines.join('\n')
}

// ---------------------------------------------------------------------------
// Internal helpers
// ---------------------------------------------------------------------------

function isFile(p: string): boolean {
  try { return statSync(p).isFile() } catch { return false }
}

