/**
 * Locale — project language detection.
 * Port of scripts/_locale_utils.py
 */

import { existsSync, readdirSync, statSync, openSync, readSync, closeSync } from 'node:fs'
import { join, extname } from 'node:path'

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

const TEXT_EXTENSIONS: ReadonlySet<string> = new Set(['.md', '.txt'])
const CJK_RE = /[\u3400-\u4dbf\u4e00-\u9fff]/g
const LATIN_RE = /[A-Za-z]/g
const MIN_LATIN_SIGNAL = 3

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

export function normalizeLocale(value: string, root?: string): string {
  let normalized = (value ?? '').trim().toLowerCase()
  if (normalized === '' || normalized === 'auto') {
    normalized = (root ? detectRepoLocale(root) : null) ?? detectSystemLocale()
  }

  const mapping: Record<string, string> = {
    'en': 'en',
    'en-us': 'en',
    'en-gb': 'en',
    'zh': 'zh-cn',
    'zh-cn': 'zh-cn',
    'zh-sg': 'zh-cn',
    'zh-hans': 'zh-cn',
    'zh-hant': 'zh-cn',
    'zh-tw': 'zh-cn',
    'zh-hk': 'zh-cn',
  }
  return mapping[normalized] ?? normalized
}

export function detectRepoLocale(root: string): string | null {
  if (!existsSync(root)) return null

  let zhScore = 0
  let enScore = 0

  for (const filePath of iterRepoTextCandidates(root)) {
    const name = filePath.split(/[/\\]/).pop()?.toLowerCase() ?? ''
    if (name.includes('zh-cn') || name.includes('zh_cn')) {
      zhScore += 12
    }

    const sample = readTextSample(filePath)
    if (!sample) continue

    const cjkCount = (sample.match(CJK_RE) ?? []).length
    const latinCount = (sample.match(LATIN_RE) ?? []).length

    if (cjkCount >= 8 && cjkCount >= Math.max(4, Math.floor(latinCount / 4))) {
      zhScore += cjkCount
    }
    if (cjkCount === 0 && latinCount >= MIN_LATIN_SIGNAL) {
      enScore += Math.max(latinCount, 12)
      continue
    }
    if (latinCount >= 40 && latinCount >= Math.max(40, cjkCount * 4)) {
      enScore += latinCount
    }
  }

  if (zhScore === 0 && enScore === 0) return null
  if (zhScore === 0) return 'en'
  if (enScore === 0) return 'zh-cn'
  if (zhScore >= enScore * 1.25) return 'zh-cn'
  if (enScore >= zhScore * 1.25) return 'en'
  return null
}

export function detectSystemLocale(): string {
  const candidates = [
    process.env['LC_ALL'],
    process.env['LANG'],
    process.env['LANGUAGE'],
  ]
  for (const candidate of candidates) {
    const text = (candidate ?? '').toLowerCase()
    if (text.startsWith('zh') || text.includes('chinese')) {
      return 'zh-cn'
    }
  }
  return 'en'
}

// ---------------------------------------------------------------------------
// Internal helpers
// ---------------------------------------------------------------------------

function* iterRepoTextCandidates(root: string): Generator<string> {
  const seen = new Set<string>()

  for (const rel of ['AGENTS.md', 'README.md', 'README.zh-CN.md', 'README.zh_CN.md']) {
    const p = join(root, rel)
    if (existsSync(p) && isFile(p)) {
      seen.add(p)
      yield p
    }
  }

  const topLevel: string[] = []
  try {
    for (const entry of readdirSync(root)) {
      const p = join(root, entry)
      if (isFile(p) && TEXT_EXTENSIONS.has(extname(p).toLowerCase()) && !seen.has(p)) {
        topLevel.push(p)
      }
    }
  } catch {
    // ignore
  }
  topLevel.sort()
  for (const p of topLevel.slice(0, 8)) {
    seen.add(p)
    yield p
  }

  const docsDir = join(root, 'docs')
  if (existsSync(docsDir) && isDir(docsDir)) {
    let count = 0
    for (const p of walkDir(docsDir)) {
      if (count >= 12) break
      if (!isFile(p) || !TEXT_EXTENSIONS.has(extname(p).toLowerCase()) || seen.has(p)) continue
      seen.add(p)
      count++
      yield p
    }
  }
}

function walkDir(dir: string): string[] {
  const results: string[] = []
  try {
    for (const entry of readdirSync(dir, { withFileTypes: true })) {
      const p = join(dir, entry.name)
      if (entry.isDirectory()) {
        results.push(...walkDir(p))
      } else if (entry.isFile()) {
        results.push(p)
      }
    }
  } catch {
    // ignore
  }
  results.sort()
  return results
}

function readTextSample(filePath: string): string {
  try {
    const buf = Buffer.alloc(4096)
    const fd = openSync(filePath, 'r')
    const bytesRead = readSync(fd, buf, 0, 4096, 0)
    closeSync(fd)
    return buf.subarray(0, bytesRead).toString('utf-8')
  } catch {
    return ''
  }
}

function isFile(p: string): boolean {
  try { return statSync(p).isFile() } catch { return false }
}

function isDir(p: string): boolean {
  try { return statSync(p).isDirectory() } catch { return false }
}

/**
 * CLI: memorytree import — import one transcript file.
 * Port of scripts/import-transcripts.py
 */

import { existsSync } from 'node:fs'
import { resolve } from 'node:path'

import { slugify } from '../transcript/common.js'
import { defaultGlobalTranscriptRoot, inferProjectSlug, transcriptMatchesRepo } from '../transcript/discover.js'
import { importTranscript, transcriptHasContent } from '../transcript/import.js'
import { inferClient, parseTranscript } from '../transcript/parse.js'

export interface ImportOptions {
  root: string
  source: string
  client: string
  projectName: string
  globalRoot: string
  rawUploadPermission: string
  format: string
}

export async function cmdImport(options: ImportOptions): Promise<number> {
  const root = resolve(options.root)
  const source = resolve(options.source)

  if (!existsSync(root)) {
    process.stderr.write(`root does not exist: ${root}\n`)
    return 1
  }
  if (!existsSync(source)) {
    process.stderr.write(`source transcript does not exist: ${source}\n`)
    return 1
  }

  const client = inferClient(options.client, source)
  const globalRoot = options.globalRoot ? resolve(options.globalRoot) : defaultGlobalTranscriptRoot()
  const repoSlug = slugify(options.projectName.trim() || (root.split(/[/\\]/).pop() ?? ''), 'project')

  const parsed = parseTranscript(client, source)
  if (!transcriptHasContent(parsed)) {
    process.stderr.write(`source transcript does not contain any importable messages or tool events: ${source}\n`)
    return 1
  }

  const detectedProject = inferProjectSlug(parsed)
  const matchesCurrentRepo = transcriptMatchesRepo(parsed, root, repoSlug)

  const result = await importTranscript(
    parsed,
    root,
    globalRoot,
    matchesCurrentRepo ? repoSlug : detectedProject,
    matchesCurrentRepo ? options.rawUploadPermission : 'not-applicable',
    matchesCurrentRepo,
  )

  const output = {
    ...result,
    matches_current_repo: matchesCurrentRepo,
    detected_project: detectedProject,
  } as Record<string, unknown>

  if (options.format === 'json') {
    process.stdout.write(JSON.stringify(output) + '\n')
  } else {
    process.stdout.write(formatImportText(output) + '\n')
  }
  return 0
}

function formatImportText(result: Record<string, unknown>): string {
  return [
    `client: ${result['client'] ?? ''}`,
    `project: ${result['project'] ?? ''}`,
    `session_id: ${result['session_id'] ?? ''}`,
    `started_at: ${result['started_at'] ?? ''}`,
    `detected_project: ${result['detected_project'] ?? ''}`,
    `matches_current_repo: ${String(result['matches_current_repo'] ?? false).toLowerCase()}`,
    `raw_upload_permission: ${result['raw_upload_permission'] ?? ''}`,
    `message_count: ${result['message_count'] ?? 0}`,
    `tool_event_count: ${result['tool_event_count'] ?? 0}`,
    `repo_raw_path: ${result['repo_raw_path'] ?? ''}`,
    `repo_clean_path: ${result['repo_clean_path'] ?? ''}`,
    `repo_manifest_path: ${result['repo_manifest_path'] ?? ''}`,
    `global_raw_path: ${result['global_raw_path'] ?? ''}`,
    `global_clean_path: ${result['global_clean_path'] ?? ''}`,
  ].join('\n')
}

/**
 * CLI: memorytree discover — scan and import local transcripts.
 * Port of scripts/discover-transcripts.py
 */

import { existsSync } from 'node:fs'
import { resolve } from 'node:path'

import { CLIENTS, slugify } from '../transcript/common.js'
import { defaultGlobalTranscriptRoot, discoverSourceFiles, inferProjectSlug, transcriptMatchesRepo } from '../transcript/discover.js'
import { importTranscript, transcriptHasContent } from '../transcript/import.js'
import { parseTranscript } from '../transcript/parse.js'
import { toPosixPath } from '../utils/path.js'

export interface DiscoverOptions {
  root: string
  client: string
  scope: string
  projectName: string
  globalRoot: string
  rawUploadPermission: string
  limit: number
  format: string
}

export async function cmdDiscover(options: DiscoverOptions): Promise<number> {
  const root = resolve(options.root)
  if (!existsSync(root)) {
    process.stderr.write(`root does not exist: ${root}\n`)
    return 1
  }

  const repoSlug = slugify(options.projectName.trim() || (root.split(/[/\\]/).pop() ?? ''), 'project')
  const globalRoot = options.globalRoot ? resolve(options.globalRoot) : defaultGlobalTranscriptRoot()
  const requestedClients = options.client === 'all' ? CLIENTS : new Set([options.client])
  const discovered = discoverSourceFiles(requestedClients)

  const results: Record<string, unknown>[] = []
  const skipped: Record<string, string>[] = []

  for (const [client, source] of discovered) {
    if (options.limit > 0 && results.length >= options.limit) break

    let parsed
    try {
      parsed = parseTranscript(client, source)
    } catch (err: unknown) {
      skipped.push({
        client,
        source,
        reason: 'parse-error',
        error: summarizeException(err),
      })
      continue
    }

    const candidateProject = inferProjectSlug(parsed)
    const matchesCurrentRepo = transcriptMatchesRepo(parsed, root, repoSlug)

    if (!transcriptHasContent(parsed)) {
      skipped.push({ client, source, reason: 'no-importable-content', project: candidateProject })
      continue
    }

    if (options.scope === 'current-project' && !matchesCurrentRepo) {
      skipped.push({ client, source, reason: 'unrelated-project', project: candidateProject })
      continue
    }

    try {
      const result = await importTranscript(
        parsed,
        root,
        globalRoot,
        matchesCurrentRepo ? repoSlug : candidateProject,
        matchesCurrentRepo ? options.rawUploadPermission : 'not-applicable',
        matchesCurrentRepo,
      )
      results.push({ ...result, matches_current_repo: matchesCurrentRepo })
    } catch (err: unknown) {
      skipped.push({
        client,
        source,
        reason: 'import-error',
        project: candidateProject,
        error: summarizeException(err),
      })
    }
  }

  const payload = {
    repo: toPosixPath(root),
    repo_project: repoSlug,
    scope: options.scope,
    client_filter: options.client,
    discovered_count: discovered.length,
    imported_count: results.length,
    repo_mirror_count: results.filter(r => r['matches_current_repo']).length,
    global_only_count: results.filter(r => !r['matches_current_repo']).length,
    skipped_count: skipped.length,
    imports: results,
    skipped,
  }

  if (options.format === 'json') {
    process.stdout.write(JSON.stringify(payload) + '\n')
  } else {
    process.stdout.write(formatDiscoverText(payload) + '\n')
  }
  return 0
}

function formatDiscoverText(payload: Record<string, unknown>): string {
  const lines = [
    `repo: ${payload['repo'] ?? ''}`,
    `repo_project: ${payload['repo_project'] ?? ''}`,
    `scope: ${payload['scope'] ?? ''}`,
    `client_filter: ${payload['client_filter'] ?? ''}`,
    `discovered_count: ${payload['discovered_count'] ?? 0}`,
    `imported_count: ${payload['imported_count'] ?? 0}`,
    `repo_mirror_count: ${payload['repo_mirror_count'] ?? 0}`,
    `global_only_count: ${payload['global_only_count'] ?? 0}`,
    `skipped_count: ${payload['skipped_count'] ?? 0}`,
  ]

  const imports = payload['imports']
  if (Array.isArray(imports) && imports.length > 0) {
    lines.push('imports:')
    for (const item of imports.slice(0, 10)) {
      const rec = item as Record<string, unknown>
      lines.push(`- ${rec['client']} ${rec['project']} ${rec['session_id']} repo_mirror=${String(rec['matches_current_repo']).toLowerCase()}`)
    }
    if (imports.length > 10) lines.push(`- ... ${imports.length - 10} more`)
  }
  return lines.join('\n')
}

function summarizeException(err: unknown): string {
  if (err instanceof Error) return err.message.trim() || err.constructor.name
  return String(err)
}

